const text = $json.text ?? $json.cleanedText ?? "";

const body = {
  text: text,
  language: $input.first().json.language,
  entities: [
      // Standard entities
      "PERSON", "LOCATION", "EMAIL_ADDRESS", "PHONE_NUMBER",
      "HK_ID_CARD", "PASSPORT_NUMBER", "HK_PHONE_NUMBER",
      "BANK_ACCOUNT", "UNIVERSITY_ID", "CREDIT_CARD",
      "IP_ADDRESS", "MAC_ADDRESS", "URL",

      // Chinese-specific
      "PERSON_ZH",      // Basic Chinese name detection
      "ADDRESS_ZH",     // Chinese address detection

      // Enhanced Chinese name (NEW!)
      "PERSON_CHINESE"  // Expanded context redaction with surname database
    ]
};

return [
  {
    json: {
      presidioBody: body   // This will be a clean JavaScript object
    }
  }
];

// Get the original cleaned text from the preparation node
const originalText = $('Prepare Presidio Request').first().json.presidioBody.text

// Get analyzer results (may be single item or array depending on n8n version)
let analyzerResults = $input.all()

// Handle different input formats
if (!Array.isArray(analyzerResults) || analyzerResults.length === 0) {
  return [{
    json: {
      text: originalText,
      redacted_text: originalText,  // No entities found, return original
      entities_found: 0
    }
  }]
}

// Extract and clean the analyzer results
const cleanResults = analyzerResults
  .filter(item => item.json && item.json.entity_type)  // Filter out empty results
  .map(item => ({
    start: item.json.start,
    end: item.json.end,
    entity_type: item.json.entity_type,
    score: item.json.score || 0.5,
  }))
  // Filter out low confidence results (optional - adjust threshold as needed)
  .filter(item => item.score >= 0.7)

// If no valid entities after filtering
if (cleanResults.length === 0) {
  return [{
    json: {
      text: originalText,
      redacted_text: originalText,
      entities_found: 0
    }
  }]
}

// Request body for anonymizer
const requestBody = {
  text: originalText,
  analyzer_results: cleanResults,
  // Redaction configuration by entity type
  operators: {
    // High priority - use specific redaction labels
    "HK_ID_CARD": {
      type: "replace",
      value: "[REDACTED HKID]"
    },
    "PASSPORT_NUMBER": {
      type: "replace", 
      value: "[REDACTED PASSPORT]"
    },
    "CREDIT_CARD": {
      type: "replace",
      value: "[REDACTED CARD]"
    },
    "BANK_ACCOUNT": {
      type: "replace",
      value: "[REDACTED ACCOUNT]"
    },
    // Names get specific label
    "PERSON": {
      type: "replace",
      value: "[REDACTED NAME]"
    },
    // Contact info
    "EMAIL_ADDRESS": {
      type: "replace",
      value: "[REDACTED EMAIL]"
    },
    "PHONE_NUMBER": {
      type: "replace",
      value: "[REDACTED PHONE]"
    },
    "HK_PHONE_NUMBER": {
      type: "replace",
      value: "[REDACTED PHONE]"
    },
    // Addresses
    "LOCATION": {
      type: "replace",
      value: "[REDACTED LOCATION]"
    },
    "ADDRESS_EN": {
      type: "replace",
      value: "[REDACTED ADDRESS]"
    },
    "ADDRESS_ZH_TRAD": {
      type: "replace",
      value: "[REDACTED ADDRESS]"
    },
    "ADDRESS_ZH_SIMP": {
      type: "replace",
      value: "[REDACTED ADDRESS]"
    },
    // Technical identifiers
    "IP_ADDRESS": {
      type: "replace",
      value: "[REDACTED IP]"
    },
    "MAC_ADDRESS": {
      type: "replace",
      value: "[REDACTED MAC]"
    },
    // Default for anything else
    "DEFAULT": {
      type: "replace",
      value: "[REDACTED]"
    }
  }
}

return [requestBody]

const redactedText = $json.text;
const fileName = $('When Executed by Another Workflow').first().json.fileName

return [{
  json: {
    redactedText,
    fileName
  }
}];
